# board.py
"""
Class to manage the state of the Checkers game board.
"""

import numpy as np

class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def make_king(self):
        self.king = True

    def __repr__(self):
        return 'K' if self.king else ('R' if self.color == 'r' else 'B')

class Board:
    def __init__(self):
        self.board = np.array([[None for _ in range(8)] for _ in range(8)])
        self.initialize_board()

    def initialize_board(self):
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('r')
        for row in range(5, 8):
            for col in range((row + 1) % 2, 8, 2):
                self.board[row][col] = Piece('b')

    def print_board(self):
        print("   " + " ".join(str(i) for i in range(8)))
        for row in range(8):
            print(f"{row} |" + "|".join([str(piece or ' ') for piece in self.board[row]]) + "|")
```

#### `game.py`
This file will contain the `Game` class and related methods.

```python
# game.py
"""
Class to manage the flow of a Checkers game.
"""

from board import Board, Piece

class Move:
    def __init__(self, start, end):
        self.start = start
        self.end = end

    def __repr__(self):
        return f"{self.start} -> {self.end}"

class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'r'

    def switch_turn(self):
        self.current_player = 'b' if self.current_player == 'r' else 'r'

    def make_move(self, move):
        start_row, start_col = move.start
        end_row, end_col = move.end
        piece = self.board.board[start_row][start_col]
        if piece and piece.color == self.current_player:
            self.board.board[end_row][end_col] = piece
            self.board.board[start_row][start_col] = None
            if (self.current_player == 'r' and end_row == 7) or (self.current_player == 'b' and end_row == 0):
                piece.make_king()

    def check_win(self):
        if not any(piece for row in self.board.board for piece in row if piece and piece.color == self.current_player):
            return self.current_player.upper() + " wins!"
        return None
```

#### `ui.py`
This file will handle user interactions.

```python
# ui.py
"""
Module to handle user interactions.
"""

from game import Game

def get_move():
    while True:
        try:
            move = input(f"Player {Game.current_player}, enter your move (e.g., 2-3): ").split('-')
            if len(move) == 2 and all(pos.isdigit() for pos in move):
                start, end = map(int, move)
                return start, end
        except ValueError:
            print("Invalid input. Please try again.")

def main():
    game = Game()
    while True:
        game.board.print_board()
        move_data = get_move()
        move = Move(move_data[0], move_data[1])
        game.make_move(move)
        result = game.check_win()
        if result:
            print(result)
            break

if __name__ == "__main__":
    main()
```

